int main(void) {
    mongoc_client_t *client;
    mongoc_database_t *database;
    mongoc_collection_t *collection;
    mongoc_cursor_t *cursor;
    bson_t *pipeline;
    bson_t *search_stage;
    bson_t *limit_stage;
    bson_t *project_stage;
    const bson_t *doc;
    bson_error_t error;

    // Connect to MongoDB
    client = connect_to_mongodb();
    if (!client) {
        return EXIT_FAILURE;
    }

    printf("Connected to MongoDB Atlas\n");

    // Get database and collection
    database = mongoc_client_get_database(client, DATABASE_NAME);
    collection = mongoc_client_get_collection(client, DATABASE_NAME, COLLECTION_NAME);

    // Create aggregation pipeline
    pipeline = bson_new();

    // Create $search stage
    search_stage = bson_new();
    bson_t *search_spec = bson_new();
    bson_t *autocomplete_spec = bson_new();

    BSON_APPEND_UTF8(autocomplete_spec, "query", "Great");
    BSON_APPEND_UTF8(autocomplete_spec, "path", "title");

    BSON_APPEND_UTF8(search_spec, "index", "partial-match-tutorial-autocomplete");
    BSON_APPEND_DOCUMENT(search_spec, "autocomplete", autocomplete_spec);

    BSON_APPEND_DOCUMENT(search_stage, "$search", search_spec);

    // Create $limit stage
    limit_stage = bson_new();
    BSON_APPEND_INT32(limit_stage, "$limit", 10);

    // Create $project stage
    project_stage = bson_new();
    bson_t *project_spec = bson_new();
    BSON_APPEND_INT32(project_spec, "_id", 0);
    BSON_APPEND_INT32(project_spec, "title", 1);
    BSON_APPEND_DOCUMENT(project_stage, "$project", project_spec);

    // Build the pipeline array
    bson_t *stage_array = bson_new();
    BSON_APPEND_DOCUMENT(stage_array, "0", search_stage);
    BSON_APPEND_DOCUMENT(stage_array, "1", limit_stage);
    BSON_APPEND_DOCUMENT(stage_array, "2", project_stage);

    BSON_APPEND_ARRAY(pipeline, "pipeline", stage_array);

    printf("Running autocomplete search query...\n");

    // Execute the aggregation
    cursor = mongoc_collection_aggregate(collection, MONGOC_QUERY_NONE, pipeline, NULL, NULL);

    if (!cursor) {
        fprintf(stderr, "Failed to execute aggregation\n");
        goto cleanup;
    }

    printf("Results:\n");

    // Iterate through results
    while (mongoc_cursor_next(cursor, &doc)) {
        print_bson_document(doc);
    }

    // Check for errors
    if (mongoc_cursor_error(cursor, &error)) {
        fprintf(stderr, "Cursor error: %s\n", error.message);
    }

cleanup:
    // Cleanup
    if (cursor) {
        mongoc_cursor_destroy(cursor);
    }
    bson_destroy(pipeline);
    bson_destroy(search_stage);
    bson_destroy(limit_stage);
    bson_destroy(project_stage);
    bson_destroy(search_spec);
    bson_destroy(autocomplete_spec);
    bson_destroy(project_spec);
    bson_destroy(stage_array);
    mongoc_collection_destroy(collection);
    mongoc_database_destroy(database);
    cleanup_mongodb(client);

    printf("Autocomplete query completed\n");
    return EXIT_SUCCESS;
}

